// Procesar evento de Lemlist
const event = $input.first().json;
const type = event.type || ''; // emailsSent, emailsOpened, emailsClicked, emailsReplied, emailsBounced
const email = event.email || event.leadEmail || '';
const campaignName = event.campaignName || '';

let action = 'unknown';
let score_delta = 0;
let create_action = false;

switch (type) {
  case 'emailsSent':
    action = 'email_sent';
    score_delta = 0;
    break;
  case 'emailsOpened':
    action = 'email_opened';
    score_delta = 5;
    break;
  case 'emailsClicked':
    action = 'email_clicked';
    score_delta = 10;
    break;
  case 'emailsReplied':
    action = 'email_replied';
    score_delta = 20;
    create_action = true;
    break;
  case 'emailsBounced':
    action = 'email_bounced';
    score_delta = -10;
    break;
  case 'emailsUnsubscribed':
    action = 'unsubscribed';
    score_delta = -20;
    break;
}

return [{
  json: {
    email,
    action,
    score_delta,
    create_action,
    campaign_name: campaignName,
    raw_type: type,
    timestamp: new Date().toISOString()
  }
}];

const lead = $input.first().json.items[0];
const prev = $('Mapear Evento').first().json;
const newScore = Math.max(0, Math.min(100, (lead.score || 0) + prev.score_delta));

return [{
  json: {
    lead_id: lead.id,
    lead_name: lead.company_name || lead.contact_name,
    new_score: newScore,
    action: prev.action,
    create_action: prev.create_action,
    campaign_name: prev.campaign_name,
    email: prev.email
  }
}];
